#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char S[N + 1];
        scanf("%s", S);
        for (int i = 0; i < N - 1; i += 2) {
            char temp = S[i];
            S[i] = S[i + 1];
            S[i + 1] = temp;
        }
        for (int i = 0; i < N; i++) {
            S[i] = 'a' + ('z' - S[i]);
        }
        printf("%s\n", S);
    }
    return 0;
}

