    while (T--) {
        int N;
        cin >> N;
        string S;
        cin >> S;
        for (int i = 0; i < N - 1; i += 2) {
            swap(S[i], S[i + 1]);
        }
        for (int i = 0; i < N; i++) {
            S[i] = 'a' + ('z' - S[i]);
        }
        cout << S << endl;
    }
    return 0;
}

