import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String S = sc.next();
            char[] arr = S.toCharArray();
            for (int i = 0; i < N - 1; i += 2) {
                char temp = arr[i];
                arr[i] = arr[i + 1];
                arr[i + 1] = temp;
            }
            for (int i = 0; i < N; i++) {
                arr[i] = (char) ('a' + ('z' - arr[i]));
            }
            System.out.println(new String(arr));
        }
    }
}

