const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const S = readline().split('');
    for (let j = 0; j < N - 1; j += 2) {
        [S[j], S[j + 1]] = [S[j + 1], S[j]];
    }
    for (let j = 0; j < N; j++) {
        S[j] = String.fromCharCode('a'.charCodeAt(0) + ('z'.charCodeAt(0) - S[j].charCodeAt(0)));
    }
    console.log(S.join(''));
}
